   113	    unsafe fn _check_for_updates(&mut self) {
   114	        let font_serial = hb_font_get_serial(self.font);
   115	        let serial = self.serial.load(Ordering::Relaxed);
   116	        if serial == font_serial {
   117	            return;
   118	        }
   119	
   120	        let _lock = self.mutex.lock().unwrap();
   121	
   122	        let mut x_scale: i32 = 0;
   123	        let mut y_scale: i32 = 0;
   124	        hb_font_get_scale(self.font, &mut x_scale, &mut y_scale);
   125	        let upem = hb_face_get_upem(hb_font_get_face(self.font));
   126	        self.x_mult = x_scale as f32 / upem as f32;
   127	        self.y_mult = y_scale as f32 / upem as f32;
   128	
   129	        let mut num_coords: u32 = 0;
   130	        let coords = hb_font_get_var_coords_normalized(self.font, &mut num_coords);
   131	        let coords = if coords.is_null() {
   132	            &[]
   133	        } else {
   134	            std::slice::from_raw_parts(coords, num_coords as usize)
   135	        };
   136	        let all_zeros = coords.iter().all(|&x| x == 0);
   137	        // if all zeros, use Location::default()
   138	        // otherwise, use the provided coords.
   139	        // This currently doesn't seem to have a perf effect on fontations, but it's a good idea to
   140	        // check if the coords are all zeros before creating a Location.
   141	        self.location = if all_zeros {
   142	            Location::default()
   143	        } else {
   144	            let mut location = Location::new(num_coords as usize);
   145	            let coords_mut = location.coords_mut();
   146	            coords_mut
   147	                .iter_mut()
   148	                .zip(coords.iter().map(|v| NormalizedCoord::from_bits(*v as i16)))
   149	                .for_each(|(dest, source)| *dest = source);
   150	            location
   151	        };
   152	
   153	        let location = transmute::<&Location, &Location>(&self.location);
   154	        self.glyph_metrics = Some(self.font_ref.glyph_metrics(self.size, location));
   155	
   156	        self.serial.store(font_serial, Ordering::Release);
   157	    }
   158	    fn check_for_updates(&mut self) {
   159	        unsafe { self._check_for_updates() }
   160	    }
