   283	extern "C" fn _hb_fontations_glyph_name(
   284	    _font: *mut hb_font_t,
   285	    font_data: *mut ::std::os::raw::c_void,
   286	    glyph: hb_codepoint_t,
   287	    name: *mut ::std::os::raw::c_char,
   288	    size: ::std::os::raw::c_uint,
   289	    _user_data: *mut ::std::os::raw::c_void,
   290	) -> hb_bool_t {
   291	    let data = unsafe { &mut *(font_data as *mut FontationsData) };
   292	
   293	    if let Some(glyph_name) = data.glyph_names.get(GlyphId::new(glyph)) {
   294	        let glyph_name = glyph_name.as_str();
   295	        // Copy the glyph name into the buffer, up to size-1 bytes
   296	        let len = glyph_name.len().min(size as usize - 1);
   297	        unsafe {
   298	            std::slice::from_raw_parts_mut(name as *mut u8, len)
   299	                .copy_from_slice(&glyph_name.as_bytes()[..len]);
   300	            *name.add(len) = 0;
   301	        }
   302	        true as hb_bool_t
   303	    } else {
   304	        false as hb_bool_t
   305	    }
   306	}
