   314	extern "C" fn _hb_fontations_glyph_from_name(
   315	    font: *mut hb_font_t,
   316	    font_data: *mut ::std::os::raw::c_void,
   317	    name: *const ::std::os::raw::c_char,
   318	    len: ::std::os::raw::c_int,
   319	    glyph: *mut hb_codepoint_t,
   320	    _user_data: *mut ::std::os::raw::c_void,
   321	) -> hb_bool_t {
   322	    let data = unsafe { &*(font_data as *const FontationsData) };
   323	
   324	    // SAFETY: HarfBuzz guarantees the string is valid memory for `len` bytes.
   325	    let name_bytes = unsafe { std::slice::from_raw_parts(name as *const u8, len as usize) };
   326	    let name_str = match std::str::from_utf8(name_bytes) {
   327	        Ok(s) => s,
   328	        Err(_) => return false as hb_bool_t,
   329	    };
   330	
   331	    let face = unsafe { hb_font_get_face(font) };
   332	    let mut user_data_ptr: *mut c_void;
   333	
   334	    loop {
   335	        user_data_ptr =
   336	            unsafe { hb_face_get_user_data(face, std::ptr::addr_of_mut!(GLYPH_FROM_NAMES_KEY)) };
   337	        if !user_data_ptr.is_null() {
   338	            break;
   339	        }
   340	
   341	        // Build the HashMap from glyph names to IDs
   342	        let mut map = HashMap::new();
   343	        for (glyph_id, glyph_name) in data.glyph_names.iter() {
   344	            map.insert(glyph_name.to_string(), glyph_id.to_u32());
   345	        }
   346	
   347	        let boxed_map = Box::new(map);
   348	        let ptr = Box::into_raw(boxed_map) as *mut c_void;
   349	
   350	        let success = unsafe {
   351	            hb_face_set_user_data(
   352	                face,
   353	                std::ptr::addr_of_mut!(GLYPH_FROM_NAMES_KEY),
   354	                ptr,
   355	                Some(_hb_glyph_from_names_destroy),
   356	                true as hb_bool_t,
   357	            )
   358	        };
   359	
   360	        if success != false as hb_bool_t {
   361	            user_data_ptr = ptr;
   362	            break;
   363	        }
   364	
   365	        // We failed to set user data — reclaim the pointer to avoid leaking
   366	        _hb_glyph_from_names_destroy(ptr);
   367	        // Try again in next loop iteration
   368	    }
   369	
   370	    let glyph_from_names = unsafe { &*(user_data_ptr as *const HashMap<String, u32>) };
   371	
   372	    match glyph_from_names.get(name_str) {
   373	        Some(gid) => {
   374	            unsafe { *glyph = *gid };
   375	            true as hb_bool_t
   376	        }
   377	        None => false as hb_bool_t,
   378	    }
   379	}
